    businessOrder := []string{"electronics", "grocery", "pharmacy", "restaurant"}

    // Filter valid coupons
    var validCoupons []struct {
        code        string
        businessLine string
    }

    for i := 0; i < len(code); i++ {
        // Check if code is not empty and only contains allowed characters
        isValidCode := false
        if code[i] != "" {
            isValidCode = true
