                    isValidCode = false
                    break
                }
            }
        }

        // Check if business line is valid
        isValidBusiness := false
        for _, b := range businessOrder {
            if b == businessLine[i] {
                isValidBusiness = true
                break
            }
        }

        // Check if active
        isActiveBool := isActive[i]

        if isValidCode && isValidBusiness && isActiveBool {
            validCoupons = append(validCoupons, struct {
                code        string
                businessLine string
            }{code[i], businessLine[i]})
        }
    }

    // Sort by business line order and then by code dictionary order
    sort.Slice(validCoupons, func(i, j int) bool {
        businessIndexI := -1
        for k, b := range businessOrder {
            if b == validCoupons[i].businessLine {
                businessIndexI = k
                break
            }
        }

        businessIndexJ := -1
        for k, b := range businessOrder {
            if b == validCoupons[j].businessLine {
                businessIndexJ = k
                break
            }
